      "path": "src/modules/tasks/service.js",
      "content": "const projectService = require('../projects/service');
const { randomUUID } = require('node:crypto');
const { sendError } = require('../../lib/errors');

function getTasks(projectId) {
  const project = projectService.getAllProjects().find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  return project.tasks;
}

function createTask(projectId, name) {
  const project = projectService.getAllProjects().find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  const task = { id: randomUUID(), name, status: 'todo' };
  project.tasks.push(task);
  return task;
}

function updateTask(projectId, taskId, status) {
  const project = projectService.getAllProjects().find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  const task = project.tasks.find(t => t.id === taskId);
  if (!task) {
    return null;
  }
  task.status = status;
  return task;
}

module.exports = {
  getTasks,
  createTask,
  updateTask,
};
